// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxProject) predicate.UxProject {
	return predicate.UxProject(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxProject) predicate.UxProject {
	return predicate.UxProject(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxProject) predicate.UxProject {
	return predicate.UxProject(sql.NotPredicates(p))
}
